#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <assert.h>
#include <sys/time.h>
#include <math.h>
#include <utility>

#define NTX 16
#define NTY 16

double stop_watch(double t0)
{
  double time;
  struct timeval t;
  gettimeofday(&t, NULL);
  time = t.tv_sec * 1e6 + t.tv_usec;
  return time-t0;
}

void usage(char *argv[]) {
  fprintf(stderr, " Usage: %s LX LY NITER\n", argv[0]);
  return;
}

__global__ void dev_lapl_iter(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  int x = blockIdx.x * blockDim.x + threadIdx.x;
  int y = blockIdx.y * blockDim.y + threadIdx.y;
  if (x < Lx && y < Ly) {
    int v00 = y*Lx + x;
    int v0p = y*Lx + (x + 1)%Lx;
    int v0m = y*Lx + (Lx + x - 1)%Lx;
    int vp0 = ((y+1)%Ly)*Lx + x;
    int vm0 = ((Ly+y-1)%Ly)*Lx + x;
    out[v00] = norm*in[v00] + delta*(in[v0p] + in[v0m] + in[vp0] + in[vm0]);
  }
}

void reference(float *out, const float *in, const float delta, const float norm, const int Lx, const int Ly)
{
  for (int y = 0; y < Ly; y++) {
    for (int x = 0; x < Lx; x++) {
      int v00 = y*Lx + x;
      int v0p = y*Lx + (x + 1)%Lx;
      int v0m = y*Lx + (Lx + x - 1)%Lx;
      int vp0 = ((y+1)%Ly)*Lx + x;
      int vm0 = ((Ly+y-1)%Ly)*Lx + x;
      out[v00] = norm*in[v00] + delta*(in[v0p] + in[v0m] + in[vp0] + in[vm0]);
    }
  }
}

int main(int argc, char *argv[]) {

  if(argc != 4) {
    usage(argv);
    exit(1);
  }


  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (Lx % NTX != 0 ||  0 != Ly % NTY) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
          NTX, NTY);
    exit(1);
  }

  int niter = atoi(argv[3]);
  assert(niter >= 1);


  const float sigma = 0.01f;
  const float xdelta = sigma / (1.0f+4.0f*sigma);
  const float xnorm = 1.0f/(1.0f+4.0f*sigma);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", niter);


  srand(123);
  float *buffer = (float*) malloc(sizeof(float)*Lx*Ly);
  float *h_out = (float*) malloc(sizeof(float)*Lx*Ly);
  float *h_in  = (float*) malloc(sizeof(float)*Lx*Ly);

  // Initialize buffer to zero to avoid uninitialized values
  memset(buffer, 0, sizeof(float)*Lx*Ly);

  int i, j, x, y;
  for (i = 0; i < Lx; i += 16) {
    x = rand() % Lx;
    for (j = 0; Ly > j; j++)
       buffer[x + j*Lx] = 1.f;
  }
  for (i = 0; Ly > i; i += 16) {
    y = rand() % Ly;
    for (j = 0; Lx > j; j++)
       buffer[j + y*Lx] = 1.f;
  }
  memcpy(h_in, buffer, sizeof(float)*Lx*Ly);

  for(i=0; niter > i; i++) {
    reference (h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }

  float *d_out, *d_in;
  cudaMalloc(&d_out, sizeof(float)*Lx*Ly);
  cudaMalloc(&d_in, sizeof(float)*Lx*Ly);
  cudaMemcpy(d_in, buffer, sizeof(float)*Lx*Ly, cudaMemcpyHostToDevice);

  double t0;

  dim3 block(NTX, NTY);
  dim3 grid(Lx/NTX, Ly/NTY);

  t0 = stop_watch(0);
  for(i=0; niter > i; i++) {
    dev_lapl_iter<<<grid, block>>>(d_out, d_in, xdelta, xnorm, Lx, Ly);
    cudaDeviceSynchronize();
    float *tmp = d_out; d_out = d_in; d_in = tmp;
  }
  t0 = stop_watch(t0)/(double)niter;

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
  	 niter, Lx, Ly, t0,
  	 Lx*Ly*sizeof(float)*2.0/(t0*1.0e3),
  	 (Lx*Ly*6.0)/(t0*1.0e3));

  cudaMemcpy(buffer, d_in, sizeof(float)*Lx*Ly, cudaMemcpyDeviceToHost);

  bool ok = true;
  for (i = 0; Lx*Ly > i; i++) {
    if ( fabs(h_in[i] - buffer[i]) > 1e-2f ) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], buffer[i]);
      ok = false;
      break;
    }
  }
  if (ok) {
    printf("PASS\n");
  } else {
    printf("FAIL\n");
  }

  free(buffer);
  free(h_out);
  free(h_in);
  cudaFree(d_in);
  cudaFree(d_out);
  return 0;
}
